INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ressão de género ou características sexuais, deficiência física ou psíquica;
  c) Ameaçar pessoa ou grupo de pessoas por causa da sua origem étnico-racial, origem nacional ou religiosa, cor, nacionalidade, ascendência, território de origem, religião, língua, sexo, orientação sexual, identidade ou expressão de género ou características sexuais, deficiência física ou psíquica; ou
  d) Incitar à discriminação, ao ódio ou à violência contra pessoa ou grupo de pessoas por causa da sua origem étnico-racial, origem nacional ou religiosa, cor, nacionalidade, ascendência, território de origem, religião, língua, sexo, orientação sexual, identidade ou expressão de género ou características sexuais, deficiência física ou psíquica;
  é punido com pena de prisão de 6 meses a 5 anos.
  3 - Quando os crimes previstos nos números anteriores forem cometidos através de sistema informático, o tribunal pode ordenar a eliminação de dados informáticos ou conteúdos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 65/98, de 02 de Setembro   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 19/2013, de 21 de Fevereiro   - Lei n.º 94/2017, de 23 de Agosto   - Lei n.º 4/2024, de 15 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 65/98, de 02 de Setembro    - 3ª versão: Lei n.º 59/2007, de 04 de Setembro    - 4ª versão: Lei n.º 19/2013, de 21 de Fevereiro    - 5ª versão: Lei n.º 94/2017, de 23 de Agosto   
     
                         
                          
  Artigo 241.º Crimes de guerra contra civis
                            
                           
                             
                               
                             
     Revogado pela Lei n.º 31/2004, 22 de Julho            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 31/2004, de 22 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 242.º Destruição de monumentos
                            
                           
                             
                               
                             
     Revogado pela Lei n.º 31/2004, 22 de Julho            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 31/2004, de 22 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 243.º Tortura e outros tratamentos cruéis, degradantes ou desumanos
                            
                           
                             
                               
                             
     1 - Quem, tendo por função a prevenção, perseguição, investigação ou conhecimento de infracções criminais, contra-ordenacionais ou disciplinares, a execução de sanções da mesma natureza ou a p','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rotecção, guarda ou vigilância de pessoa detida ou presa, a torturar ou tratar de forma cruel, degradante ou desumana para: 
  a) Obter dela ou de outra pessoa confissão, depoimento, declaração ou informação; 
  b) A castigar por acto cometido ou supostamente cometido por ela ou por outra pessoa; ou 
  c) A intimidar ou para intimidar outra pessoa;
  é punido com pena de prisão de 1 a 5 anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Na mesma pena incorre quem, por sua iniciativa ou por ordem de superior, usurpar a função referida no numero anterior para praticar qualquer dos actos aí descritos. 
  3 - Considera-se tortura, tratamento cruel, degradante ou desumano, o acto que consista em infligir sofrimento físico ou psicológico agudo, cansaço físico ou psicológico grave ou no emprego de produtos químicos, drogas ou outros meios, naturais ou artificiais, com intenção de perturbar a capacidade de determinação ou a livre manifestação de vontade da vítima. 
  4 - O disposto no número anterior não abrange os sofrimentos inerentes à execução das sanções previstas no n.º 1 ou por ela ocasionados, nem as medidas legais privativas ou restritivas da liberdade.            
         
   
     
                         
                          
  Artigo 244.º Tortura e outros tratamentos cruéis, degradantes ou desumanos graves
                            
                           
                             
                               
                             
     1 - Quem, nos termos e condições referidos no artigo anterior:
  a) Produzir ofensa à integridade física grave;
  b) Empregar meios ou métodos de tortura particularmente graves, designadamente espancamentos, electrochoques, simulacros de execução ou substâncias alucinatórias; ou 
  c) Praticar habitualmente actos referidos no artigo anterior;
  é punido com pena de prisão de 3 a 12 anos.
  2 - Se dos factos descritos neste artigo ou no artigo anterior resultar suicídio ou morte da vítima, o agente é punido com pena de prisão de 8 a 16 anos.            
         
   
     
                         
                          
  Artigo 245.º Omissão de denúncia
                            
                           
                             
                               
                             
     O superior hierárquico que, tendo conhecimento da prática, por subordinado, de facto descrito nos artigos 243.º ou 244.º, não fizer a denúncia no prazo máximo de 3 dias após o conhecimento, é punido com pena de prisão de 6 meses a 3 anos.            
         
   
     
                         
                          
  Artigo 246.º Incapacidades
                            
                           
                             
                               
                             
     Quem for condenado por crime previsto nos artigos 240.º e 243.º a 245.º pode, atenta a concreta gravidade do facto e a sua projecção na idoneid','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ade cívica do agente, ser incapacitado para eleger o Presidente da República, os deputados à Assembleia da República, os deputados ao Parlamento Europeu, os deputados às Assembleias Legislativas das Regiões Autónomas e os titulares dos órgãos das autarquias locais, para ser eleito como tal ou para ser jurado, por período de dois a dez anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 31/2004, de 22 de Julho   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 31/2004, de 22 de Julho   
     
                         
                          
TÍTULO IV
  Dos crimes contra a vida em sociedade
  CAPÍTULO I
  Dos crimes contra a família, os sentimentos religiosos e o respeito devido aos mortos 
  SECÇÃO I
  Dos crimes contra a família  Artigo 247.º Bigamia
                            
                           
                             
                               
                             
     Quem:
  a) Sendo casado, contrair outro casamento; ou
  b) Contrair casamento com pessoa casada;
  é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.            
         
   
     
                         
                          
  Artigo 248.º Falsificação de estado civil
                            
                           
                             
                               
                             
     Quem:
  a) Fizer figurar no registo civil nascimento inexistente; ou
  b) De maneira a pôr em perigo a verificação oficial de estado civil ou de posição jurídica familiar, usurpar, alterar, supuser ou encobrir o seu estado civil ou a posição jurídica familiar de outra pessoa; 
  é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.            
         
   
     
                         
                          
  Artigo 249.º Subtracção de menor
                            
                           
                             
                               
                             
     1 - Quem: 
  a) Subtrair menor; 
  b) Por meio de violência ou de ameaça com mal importante determinar menor a fugir; ou 
  c) De um modo repetido e injustificado, não cumprir o regime estabelecido para a convivência do menor na regulação do exercício das responsabilidades parentais, ao recusar, atrasar ou dificultar significativamente a sua entrega ou acolhimento; 
  é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Nos casos previstos na alínea c) do n.º 1, a pena é especialmente atenuada quando a conduta do agente tiver sido condicionada pelo respeito pela vontade do menor com idade superior a 12 anos. 
  3 - O procedimento criminal depende de queixa.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 61/2008, de 31 de Outub','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro   
     
                         
                          
  Artigo 250.º Violação da obrigação de alimentos
                            
                           
                             
                               
                             
     1 - Quem, estando legalmente obrigado a prestar alimentos e em condições de o fazer, não cumprir a obrigação no prazo de dois meses seguintes ao vencimento, é punido com pena de multa até 120 dias. 
  2 - A prática reiterada do crime referido no número anterior é punível com pena de prisão até um ano ou com pena de multa até 120 dias. 
  3 -Quem, estando legalmente obrigado a prestar alimentos e em condições de o fazer, não cumprir a obrigação, pondo em perigo a satisfação, sem auxílio de terceiro, das necessidades fundamentais de quem a eles tem direito, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias.  
  4 - Quem, com a intenção de não prestar alimentos, se colocar na impossibilidade de o fazer e violar a obrigação a que está sujeito criando o perigo previsto no número anterior, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  5 - O procedimento criminal depende de queixa. 
  6 - Se a obrigação vier a ser cumprida, pode o tribunal dispensar de pena ou declarar extinta, no todo ou em parte, a pena ainda não cumprida.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 61/2008, de 31 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro   
     
                         
                          
SECÇÃO II
  Dos crimes contra sentimentos religiosos  Artigo 251.º Ultraje por motivo de crença religiosa
                            
                           
                             
                               
                             
     1 - Quem publicamente ofender outra pessoa ou dela escarnecer em razão da sua crença ou função religiosa, por forma adequada a perturbar a paz pública, é punido com pena de prisão até 1 ano ou com pena de multa até 120 dias. 
  2 - Na mesma pena incorre quem profanar lugar ou objecto de culto ou de veneração religiosa, por forma adequada a perturbar a paz pública.            
         
   
     
                         
                          
  Artigo 252.º Impedimento, perturbação ou ultraje a acto de culto
                            
                           
                             
                               
                             
     Quem:
  a) Por meio de violência ou de ameaça com mal importante impedir ou perturbar o exercício legítimo do culto de religião; ou 
  b) Publicamente vilipendiar acto de culto de religião ou dele escarnecer;
  é punido','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' com pena de prisão até 1 ano ou com pena de multa até 120 dias.            
         
   
     
                         
                          
SECÇÃO III
  Dos crimes contra o respeito devido aos mortos  Artigo 253.º Impedimento ou perturbação de cerimónia fúnebre
                            
                           
                             
                               
                             
     Quem, por meio de violência ou de ameaça com mal importante, impedir ou perturbar a realização de cortejo ou de cerimónia fúnebre, é punido com pena de prisão até 1 ano ou com pena de multa até 120 dias.            
         
   
     
                         
                          
  Artigo 254.º Profanação de cadáver ou de lugar fúnebre
                            
                           
                             
                               
                             
     1 - Quem:
  a) Sem autorização de quem de direito, subtrair, destruir ou ocultar cadáver ou parte dele, ou cinzas de pessoa falecida; 
  b) Profanar cadáver ou parte dele, ou cinzas de pessoa falecida, praticando actos ofensivos do respeito devido aos mortos; ou 
  c) Profanar lugar onde repousa pessoa falecida ou monumento aí erigido em sua memória, praticando actos ofensivos do respeito devido aos mortos; 
  é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.
  2 - A tentativa é punível.            
         
   
     
                         
                          
  CAPÍTULO II 
  Dos crimes de falsificação 
  SECÇÃO I 
  Disposição preliminar  Artigo 255.º 
Definições legais
                            
                           
                             
                               
                             
     Para efeito do disposto no presente capítulo considera-se:
  a) Documento - a declaração corporizada em escrito, ou registada em disco, fita gravada ou qualquer outro meio técnico, inteligível para a generalidade das pessoas ou para um certo círculo de pessoas, que, permitindo reconhecer o emitente, é idónea para provar facto juridicamente relevante, quer tal destino lhe seja dado no momento da sua emissão, quer posteriormente; e bem assim o sinal materialmente feito, dado ou posto numa coisa ou animal para provar facto juridicamente relevante e que permite reconhecer à generalidade das pessoas ou a um certo círculo de pessoas o seu destino e a prova que dele resulta;
  b) Notação técnica - a notação de um valor, de um peso ou de uma medida, de um estado ou do decurso de um acontecimento, feita através de aparelho técnico que actua, total ou parcialmente, de forma automática, que permite reconhecer à generalidade das pessoas ou a um certo círculo de pessoas os seus resultados e se destina à prova de facto juridicamente relevante, quer tal destino lhe seja dado no momento da sua realização quer posteriormente; 
  c) Documento de identificação ou de viagem - o cartão de cidadão, o bilhet','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e de identidade, o passaporte, o visto, a autorização ou título de residência, a carta de condução, o boletim de nascimento, a cédula ou outros certificados ou atestados a que a lei atribui força de identificação das pessoas, ou do seu estado ou situação profissional, donde possam resultar direitos ou vantagens, designadamente no que toca a subsistência, aboletamento, deslocação, assistência, saúde ou meios de ganhar a vida ou de melhorar o seu nível; 
  d) Moeda - o papel moeda, compreendendo as notas de banco, e a moeda metálica, que tenham, esteja legalmente previsto que venham a ter ou tenham tido nos últimos 20 anos curso legal em Portugal ou no estrangeiro.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 97/2001, de 25 de Agosto   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 8/2017, de 03 de Março
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 97/2001, de 25 de Agosto    - 3ª versão: Lei n.º 59/2007, de 04 de Setembro   
     
                         
                          
SECÇÃO II 
  Falsificação de documentos  Artigo 256.º Falsificação ou contrafacção de documento
                            
                           
                             
                               
                             
     1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, de obter para si ou para outra pessoa benefício ilegítimo, ou de preparar, facilitar, executar ou encobrir outro crime: 
  a) Fabricar ou elaborar documento falso, ou qualquer dos componentes destinados a corporizá-lo; 
  b) Falsificar ou alterar documento ou qualquer dos componentes que o integram; 
  c) Abusar da assinatura de outra pessoa para falsificar ou contrafazer documento; 
  d) Fizer constar falsamente de documento ou de qualquer dos seus componentes facto juridicamente relevante; 
  e) Usar documento a que se referem as alíneas anteriores; ou 
  f) Por qualquer meio, facultar ou detiver documento falsificado ou contrafeito; 
  é punido com pena de prisão até três anos ou com pena de multa. 
  2 - A tentativa é punível. 
  3 - Se os factos referidos no n.º 1 disserem respeito a documento autêntico ou com igual força, a testamento cerrado, a vale do correio, a letra de câmbio, a cheque ou a outro documento comercial transmissível por endosso, ou a qualquer outro título de crédito não compreendido no artigo 267.º, o agente é punido com pena de prisão de seis meses a cinco anos ou com pena de multa de 60 a 600 dias. 
  4 - Se os factos referidos nos n.os 1 e 3 forem praticados por funcionário, no exercício das suas funções, o agente é punido com pena de prisão de um a cinco anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                       ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('   
  Artigo 257.º Falsificação praticada por funcionário
                            
                           
                             
                               
                             
     O funcionário que, no exercício das suas funções:
  a) Omitir em documento, a que a lei atribui fé pública, facto que esse documento se destina a certificar ou autenticar; ou 
  b) Intercalar acto ou documento em protocolo, registo ou livro oficial, sem cumprir as formalidades legais; 
  com intenção de causar prejuízo a outra pessoa ou ao Estado, ou de obter para si ou para outra pessoa benefício ilegítimo, é punido com pena de prisão de 1 a 5 anos.            
         
   
     
                         
                          
  Artigo 258.º Falsificação de notação técnica
                            
                           
                             
                               
                             
     1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, ou de obter para si ou para outra pessoa benefício ilegítimo: 
  a) Fabricar notação técnica falsa;
  b) Falsificar ou alterar notação técnica;
  c) Fizer constar falsamente de notação técnica facto juridicamente relevante; ou 
  d) Fizer uso de notação técnica a que se referem as alíneas anteriores, falsificada por outra pessoa; 
  é punido com pena de prisão até 3 anos ou com pena de multa.
  2 - É equiparável à falsificação de notação técnica a acção perturbadora sobre aparelhos técnicos ou automáticos por meio da qual se influenciem os resultados da notação. 
  3 - A tentativa é punível.
  4 - É correspondentemente aplicável o disposto no n.º 4 do artigo 256.º            
         
   
     
                         
                          
  Artigo 259.º Danificação ou subtracção de documento e notação técnica
                            
                           
                             
                               
                             
     1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, ou de obter para si ou para outra pessoa benefício ilegítimo, destruir, danificar, tornar não utilizável, fizer desaparecer, dissimular ou subtrair documento ou notação técnica, de que não pode ou não pode exclusivamente dispor, ou de que outra pessoa pode legalmente exigir a entrega ou apresentação, é punido com pena de prisão até 3 anos ou com pena de multa. 
  2 - A tentativa é punível.
  3 - É correspondentemente aplicável o disposto no n.º 4 do artigo 256.º
  4 - Quando sejam particulares os ofendidos, o procedimento criminal depende de queixa.            
         
   
     
                         
                          
  Artigo 260.º Atestado falso
                            
                           
                             
                               
                             
     1 - O médico, dentista, enfermeiro, parteira, dirigente ou empregado de laboratório ou de instit','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('uição de investigação que sirva fins médicos, ou pessoa encarregada de fazer autópsias, que passar atestado ou certificado que sabe não corresponder à verdade, sobre o estado do corpo ou da saúde física ou mental, o nascimento ou a morte de uma pessoa, destinado a fazer fé perante autoridade pública ou a prejudicar interesses de outra pessoa, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Na mesma pena incorre o veterinário que passar atestados nos termos e com os fins descritos no número anterior relativamente a animais. 
  3 - Na mesma pena incorrem as pessoas referidas nos números anteriores que passarem atestado ou certificado ignorando se correspondem à verdade os factos deles constantes. 
  4 - Na mesma pena incorre quem passar atestado ou certificado referido nos n.os 1 e 2 arrogando-se falsamente as qualidades ou funções neles referidas. 
  5 - Quem fizer uso dos referidos certificados ou atestados falsos, com o fim de enganar autoridade pública ou prejudicar interesses de outra pessoa, é punido com pena de prisão até um ano ou com pena de multa até 120 dias.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 261.º Uso de documento de identificação ou de viagem alheio
                            
                           
                             
                               
                             
     1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, de obter para si ou para outra pessoa benefício ilegítimo, ou de preparar, facilitar, executar ou encobrir outro crime, utilizar documento de identificação ou de viagem emitido a favor de outra pessoa, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Na mesma pena incorre quem, com intenção de tornar possível o facto descrito no número anterior, facultar documento de identificação ou de viagem a pessoa a favor de quem não foi emitido.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
SECÇÃO III 
  Falsificação de moeda, título de crédito e valor selado  Artigo 262.º Contrafacção de moeda
                            
                           
                             
                               
                             
     1 - Quem praticar contrafacção de moeda, com intenção de a pôr em circulação como legítima, é punido com pena de prisão de três a doze anos. 
  2 - Quem, com a intenção de a pôr em circulação, falsificar ou alterar o valor facial de moeda legítima para valor superior é punido com pena de prisão de dois a oito anos.     ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 97/2001, de 25 de Agosto   - Rectif. n.º 102/2007, de 31 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 97/2001, de 25 de Agosto   
     
                         
                          
  Artigo 263.º Depreciação do valor de moeda metálica
                            
                           
                             
                               
                             
     1 - Quem, com intenção de a pôr em circulação como íntegra, depreciar moeda metálica legítima, diminuindo por qualquer modo o seu valor, é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias. 
  2 - Com a mesma pena é punido quem, sem autorização legal e com intenção de a passar ou pôr em circulação, fabricar moeda metálica com o mesmo ou com maior valor que o da legítima. 
  3 - A tentativa é punível.            
         
   
     
                         
                          
  Artigo 264.º Passagem de moeda falsa de concerto com o falsificador
                            
                           
                             
                               
                             
     1 - Nas penas indicadas nos artigos 262.º e 263.º incorre quem, concertando-se com o agente dos factos neles descritos, passar ou puser em circulação por qualquer modo, incluindo a exposição à venda, as ditas moedas. 
  2 - A tentativa é punível.            
         
   
     
                         
                          
  Artigo 265.º 
Passagem de moeda falsa
                            
                           
                             
                               
                             
     1 - Quem, por qualquer modo, incluindo a exposição à venda, passar ou puser em circulação:
  a) Como legítima ou intacta, moeda falsa, falsificada, fabricada sem autorização legal ou em desrespeito pelas condições em que as autoridades competentes podem emitir moeda; ou
  b) Moeda metálica depreciada, pelo seu pleno valor; ou
  c) (Revogada.)
  é punido, no caso da alínea a), com pena de prisão até 5 anos e, no caso da alínea b), com pena de prisão até 1 ano ou com pena de multa até 120 dias.
  2 - Se o agente só tiver conhecimento de que a moeda é falsa ou falsificada depois de a ter recebido, é punido:
  a) No caso de alínea a) do número anterior, com prisão até 1 ano ou multa até 240 dias;
  b) No caso da alínea b) do número anterior, com pena de multa até 90 dias.
  3  (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 97/2001, de 25 de Agosto   - Lei n.º 39/2016, de 19 de Dezembro   - Lei n.º 79/2021, de 24 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 97/2001, de 25 de Agosto    - 3ª versão: Lei n.º 39/2016, de 19 de Dezembro   
   ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  
                         
                          
  Artigo 266.º 
Aquisição de moeda falsa para ser posta em circulação
                            
                           
                             
                               
                             
     1 - Quem adquirir, receber em depósito, transportar, exportar, importar ou por outro modo introduzir em território português, para si ou para outra pessoa, com intenção de, por qualquer meio, incluindo a exposição à venda, a passar ou pôr em circulação: 
  a) Como legítima ou intacta, moeda falsa, falsificada, fabricada sem autorização legal ou em desrespeito pelas condições em que as autoridades competentes podem emitir moeda; ou
  b) Moeda metálica depreciada, pelo seu pleno valor; ou
  c) (Revogada.)
  é punido, no caso da alínea a), com pena de prisão até 5 anos e, no caso da alínea b), com pena de prisão até 6 meses ou com pena de multa até 60 dias.
  2 - A tentativa é punível.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 97/2001, de 25 de Agosto   - Lei n.º 39/2016, de 19 de Dezembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 97/2001, de 25 de Agosto   
     
                         
                          
  Artigo 267.º 
Títulos equiparados a moeda
                            
                           
                             
                               
                             
     1 - Para efeitos do disposto nos artigos 262.º a 266.º, são equiparados a moeda:
  a) Os títulos de crédito nacionais e estrangeiros constantes, por força da lei, de um tipo de papel e de impressão especialmente destinados a garanti-los contra o perigo de imitações e que, pela sua natureza e finalidade, não possam, só por si, deixar de incorporar um valor patrimonial;
  b) Os bilhetes ou fracções da lotaria nacional; e
  c) Os cartões de garantia.
  2 - O disposto no número anterior não abrange a falsificação relativamente a elementos a cuja garantia e identificação especialmente se não destine o uso do papel ou da impressão.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 79/2021, de 24 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 268.º Contrafacção de valores selados
                            
                           
                             
                               
                             
     1 - Quem, com intenção de os empregar ou de, por qualquer forma, incluindo a exposição à venda, os pôr em circulação como legítimos ou intactos, praticar contrafacção ou falsificação de valores selados ou timbrados cujo fornecimento seja exclusivo do Estado Português, nomeadamente papel selado de letra, selos fiscais ou postais, é punido com pena de prisão de 1 a 5 anos. 
  2 ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('- Quem:
  a) Empregar como legítimos ou intactos os referidos valores selados ou timbrados, quando falsos ou falsificados; ou 
  b) Com a intenção referida no n.º 1, adquirir, receber em depósito, importar ou por outro modo introduzir em território português, para si ou para outra pessoa, os referidos valores selados ou timbrados, quando falsos ou falsificados; 
  é punido com pena de prisão até 3 anos ou com pena de multa.
  3 - Se, no caso da alínea a) do número anterior, o agente só tiver tido conhecimento de que os valores selados ou timbrados são falsos ou falsificados depois de os ter recebido, é punido com pena de multa até 90 dias. 
  4 - Se a falsificação consistir em fazer desaparecer dos referidos valores selados ou timbrados o sinal de já haverem servido, o agente é punido com pena de multa até 60 dias.            
         
   
     
                         
                          
SECÇÃO IV
  Falsificação de cunhos, pesos e objectos análogos  Artigo 269.º Contrafacção de selos, cunhos, marcas ou chancelas
                            
                           
                             
                               
                             
     1 - Quem, com intenção de os empregar como autênticos ou intactos, contrafizer ou falsificar selos, cunhos, marcas ou chancelas de qualquer autoridade ou repartição pública é punido com pena de prisão de 1 a 5 anos. 
  2 - Quem, com a referida intenção, adquirir, receber em depósito, importar, ou por outro modo introduzir em território português, para si ou para outra pessoa, os objectos referidos no número anterior, quando falsos ou falsificados, é punido com pena de prisão até 3 anos ou com pena de multa. 
  3 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, utilizar, sem autorização de quem de direito, objectos referidos no n.º 1, é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.            
         
   
     
                         
                          
  Artigo 270.º Pesos e medidas falsos
                            
                           
                             
                               
                             
     1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado:
  a) Apuser sobre pesos, medidas, balanças ou outros instrumentos de medida uma punção falsa ou tiver falsificado a existente; 
  b) Alterar, qualquer que seja a sua natureza, pesos, medidas, balanças ou outros instrumentos de medida, que estejam sujeitos legalmente à existência de uma punção; ou 
  c) Utilizar pesos, medidas, balanças ou outros instrumentos de medida falsos ou falsificados; 
  é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.
  2 - A tentativa é punível.            
         
   
     
                         
                          
SECÇÃO V 
  Disposição comum  Artigo 271.º Actos preparatórios
                            
                           
                 ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('            
                               
                             
     1 - Quem preparar a execução dos actos referidos nos artigos 256.º, 262.º, 263.º, no n.º 1 do artigo 268.º, no n.º 1 do artigo 269.º, ou no artigo 270.º, fabricando, importando, adquirindo para si ou para outra pessoa, fornecendo, expondo à venda ou retendo: 
  a) Formas, cunhos, clichés, prensas de cunhar, punções, negativos, fotografias ou outros instrumentos que, pela sua natureza, são utilizáveis para realizar crimes; ou 
  b) Papel, holograma ou outro elemento igual ou susceptível de se confundir com os que são particularmente fabricados para evitar imitações ou utilizados no fabrico de documento autêntico ou de igual valor, moeda, título de crédito ou valor selado; 
  é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - É correspondentemente aplicável à falsificação dos títulos constantes do artigo 267.º o disposto no número anterior. 
  3 - Não é punível pelos números anteriores quem voluntariamente: 
  a) Abandonar a execução do acto preparado e prevenir o perigo, por ele causado, de que outra pessoa continue a preparar o acto ou o execute, ou se esforçar seriamente nesse sentido, ou impedir a consumação; e 
  b) Destruir ou inutilizar os meios ou objectos referidos nos números anteriores, ou der à autoridade pública conhecimento deles ou a ela os entregar.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
CAPÍTULO III 
  
  Dos crimes de perigo comum  Artigo 272.º Incêndios, explosões e outras condutas especialmente perigosas
                            
                           
                             
                               
                             
     1 - Quem: 
  a) Provocar incêndio de relevo, nomeadamente pondo fogo a edifício, construção ou meio de transporte; 
  b) Provocar explosão por qualquer forma, nomeadamente mediante utilização de explosivos; 
  c) Libertar gases tóxicos ou asfixiantes; 
  d) Emitir radiações ou libertar substâncias radioactivas; 
  e) Provocar inundação, desprendimento de avalanche, massa de terra ou de pedras; ou 
  f) Provocar desmoronamento ou desabamento de construção; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de três a dez anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão de um a oito anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até cinco anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª vers','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 273.º Energia nuclear
                            
                           
                             
                               
                             
     Se os factos descritos no artigo anterior forem praticados mediante libertação de energia nuclear, o agente é punido com pena de prisão: 
  a) De 5 a 15 anos no caso do n.º 1;
  b) De 3 a 10 anos no caso do n.º 2;
  c) De 1 a 8 anos no caso do n.º 3.            
         
   
     
                         
                          
  Artigo 274.º 
Incêndio florestal
                            
                           
                             
                               
                             
     1 - Quem provocar incêndio em terreno ocupado com floresta, incluindo matas, ou pastagem, mato, formações vegetais espontâneas ou em terreno agrícola, próprios ou alheios, é punido com pena de prisão de 1 a 8 anos. 
  2 - Se, através da conduta referida no número anterior, o agente: 
  a) Criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado; 
  b) Deixar a vítima em situação económica difícil; ou 
  c) Actuar com intenção de obter benefício económico; 
  é punido com pena de prisão de três a doze anos. 
  3 - Se o perigo previsto na alínea a) do n.º 2 for criado por negligência, o agente é punido com pena de prisão de dois a dez anos. 
  4 - Se a conduta prevista no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  5 - Se a conduta prevista no número anterior for praticada por negligência grosseira ou criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, o agente é punido com pena de prisão até cinco anos. 
  6 - Quem impedir o combate aos incêndios referidos nos números anteriores é punido com pena de prisão de um a oito anos. 
  7 - Quem dificultar a extinção dos incêndios referidos nos números anteriores, designadamente destruindo ou tornando inutilizável o material destinado a combatê-los, é punido com pena de prisão de um a cinco anos. 
  8 - Não é abrangida pelo disposto nos n.os 1 a 5 a realização de trabalhos e outras operações que, segundo os conhecimentos e a experiência da técnica florestal, se mostrarem indicados e forem levados a cabo, de acordo com as regras aplicáveis, por pessoa qualificada ou devidamente autorizada, para combater incêndios, prevenir, debelar ou minorar a deterioração do património florestal ou garantir a sua defesa ou conservação. 
  9  (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 56/2011, de 15 de Novembro   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Lei n.º 59/2007, de 04 de Setembro    - 3ª versão: Lei n.º 56/2011, de 15 de Novembro   
     
                         
                          
  Artigo 274.º-A 
Regime sancionatório
                            
                           
                             
                               
                             
     1 - A suspensão da execução da pena de prisão e a liberdade condicional podem ser subordinadas à obrigação de permanência na habitação, com fiscalização por meios técnicos de controlo à distância, no período coincidente com os meses de maior risco de ocorrência de fogos.
  2 - Quando qualquer dos crimes previstos no artigo anterior for cometido por inimputável, a medida de segurança prevista no artigo 91.º pode ser aplicada sob a forma de internamento coincidente com os meses de maior risco de ocorrência de fogos.
  3 - A suspensão da execução do internamento e a liberdade para prova podem ser subordinadas à obrigação de permanência na habitação, com fiscalização por meios técnicos de controlo à distância, no período coincidente com os meses de maior risco de ocorrência de fogos.
  4 - Quem praticar crime doloso de incêndio florestal a que devesse aplicar-se concretamente prisão efetiva e tiver cometido anteriormente crime doloso de incêndio florestal a que tenha sido ou seja aplicada pena de prisão efetiva, é punido com uma pena relativamente indeterminada, sempre que a avaliação conjunta dos factos praticados e da personalidade do agente revelar uma acentuada inclinação para a prática deste crime, que persista no momento da condenação.
  5 - Sem prejuízo do disposto nos n.os 1 a 3, à pena relativamente indeterminada é correspondentemente aplicável o disposto no n.º 2 do artigo 86.º e no artigo 87.º
  Aditado pelo seguinte diploma: Lei n.º 94/2017, de 23 de Agosto            
         
   
     
                         
                          
  Artigo 275.º Actos preparatórios
                            
                           
                             
                               
                             
     Quem, para preparar a execução de um dos crimes previstos nos artigos 272.º a 274.º, fabricar, dissimular, adquirir para si ou para outra pessoa, entregar, detiver ou importar substância explosiva ou capaz de produzir explosão nuclear, radioactiva ou própria para fabricação de gases tóxicos ou asfixiantes, ou aparelhagem necessária para a execução de tais crimes, é punido com pena de prisão até três anos ou com pena de multa.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 65/98, de 02 de Setembro   - Lei n.º 98/2001, de 25 de Agosto   - Lei n.º 5/2006, de 23 de Fevereiro   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 65/98, de 02 de Setembro    - 3ª versão: Lei n.º 98/2001, de 25 de Agosto    - 4ª versão: Lei n.º 5/2006, de 23 de Fevereiro ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  
     
                         
                          
  Artigo 276.º Instrumentos de escuta telefónica
                            
                           
                             
                               
                             
     Quem importar, fabricar, guardar, comprar, vender, ceder ou adquirir a qualquer título, transportar, distribuir ou detiver instrumento ou aparelhagem especificamente destinados à montagem de escuta telefónica, ou à violação de correspondência ou de telecomunicações, fora das condições legais ou em contrário das prescrições da autoridade competente, é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.            
         
   
     
                         
                          
  Artigo 277.º Infracção de regras de construção, dano em instalações e perturbação de serviços
                            
                           
                             
                               
                             
     1 - Quem: 
  a) No âmbito da sua actividade profissional infringir regras legais, regulamentares ou técnicas que devam ser observadas no planeamento, direcção ou execução de construção, demolição ou instalação, ou na sua modificação ou conservação; 
  b) Destruir, danificar ou tornar não utilizável, total ou parcialmente, aparelhagem ou outros meios existentes em local de trabalho e destinados a prevenir acidentes, ou, infringindo regras legais, regulamentares ou técnicas, omitir a instalação de tais meios ou aparelhagem; 
  c) Destruir, danificar ou tornar não utilizável, total ou parcialmente, instalação para aproveitamento, produção, armazenamento, condução ou distribuição de água, óleo, gasolina, calor, electricidade, gás ou energia nuclear, ou para protecção contra forças da natureza; ou 
  d) Impedir ou perturbar a exploração de serviços de comunicações ou de fornecimento ao público de água, luz, energia ou calor, subtraindo ou desviando, destruindo, danificando ou tornando não utilizável, total ou parcialmente, coisa ou energia que serve tais serviços; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de um a oito anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até cinco anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 278.º 
Danos contra a natureza
                            
                           
                             
                               
                         ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('    
     1 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições: 
  a) Eliminar, destruir ou capturar exemplares de espécies protegidas da fauna ou da flora selvagens ou eliminar exemplares de fauna ou flora em número significativo; 
  b) Destruir ou deteriorar significativamente habitat natural protegido ou habitat natural não protegido causando a este perdas em espécies protegidas da fauna ou da flora selvagens ou em número significativo; ou
  c) Afectar gravemente recursos do subsolo; 
  é punido com pena de prisão até 5 anos.
  2 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições, comercializar ou detiver para comercialização exemplar de espécies protegidas da fauna ou da flora selvagens, vivo ou morto, bem como qualquer parte ou produto obtido a partir daquele, é punido com pena de prisão até 2 anos ou com pena de multa até 360 dias.
  3 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições, possuir ou detiver exemplar de espécies protegidas da fauna ou da flora selvagens, vivo ou morto, é punido com pena de prisão até 1 ano ou com pena de multa até 240 dias.
  4 - A conduta referida no número anterior não é punível quando: 
  a) A quantidade de exemplares detidos não for significativa; e 
  b) O impacto sobre a conservação das espécies em causa não for significativo. 
  5 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até 2 anos ou com pena de multa até 360 dias.
  6 - Se as condutas referidas nos n.os 2 e 3 forem praticadas por negligência, o agente é punido com pena de multa até 240 dias.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 56/2011, de 15 de Novembro   - Lei n.º 81/2015, de 03 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro    - 3ª versão: Lei n.º 56/2011, de 15 de Novembro   
     
                         
                          
  Artigo 278.º-A 
Violação de regras urbanísticas
                            
                           
                             
                               
                             
     1 - Quem proceder a obra de construção, reconstrução ou ampliação de imóvel que incida sobre via pública, terreno da Reserva Ecológica Nacional, Reserva Agrícola Nacional, bem do domínio público ou terreno especialmente protegido por disposição legal, consciente da desconformidade da sua conduta com as normas urbanísticas aplicáveis, é punido com pena de prisão até três anos ou multa.
  2 - Não são puníveis as obras de escassa relevância urbanística, assim classificadas por lei.
  3  (','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Revogado.) 
  4 - Pode o tribunal ordenar, na decisão de condenação, a demolição da obra ou a restituição do solo ao estado anterior, à custa do autor do facto.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 79/2021, de 24 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 32/2010, de 02 de Setembro   
     
                         
                          
  Artigo 278.º-B Dispensa ou atenuação da pena
                            
                           
                             
                               
                             
     1 - Nos casos previstos no artigo anterior, pode haver lugar a dispensa da pena se o agente, antes da instauração do procedimento criminal, demolir a obra ou restituir o solo ao estado anterior à obra. 
  2 - A pena é especialmente atenuada se o agente demolir a obra ou restituir o solo ao estado anterior à obra até ao encerramento da audiência de julgamento em primeira instância. 
  Aditado pelo seguinte diploma: Lei n.º 32/2010, de 02 de Setembro            
         
   
     
                         
                          
  Artigo 279.º 
Poluição
                            
                           
                             
                               
                             
     1 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições, provocar poluição sonora ou poluir o ar, a água, o solo, ou por qualquer forma degradar as qualidades destes componentes ambientais, causando danos substanciais, é punido com pena de prisão até 5 anos.
  2 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições, causar danos substanciais à qualidade do ar, da água, do solo, ou à fauna ou à flora, ao proceder:
  a) À descarga, à emissão ou à introdução de matérias ionizantes ou de radiações ionizantes na atmosfera, no solo ou na água;
  b) Às operações de recolha, transporte, armazenagem, triagem, tratamento, valorização e eliminação de resíduos, incluindo o tratamento posterior dos locais de eliminação, bem como as actividades exercidas por negociantes e intermediários; 
  c) À exploração de instalação onde se exerça atividade perigosa ou onde sejam armazenadas ou utilizadas substâncias ou misturas perigosas; ou
  d) À produção, ao tratamento, à manipulação, à utilização, à detenção, ao armazenamento, ao transporte, à importação, à exportação ou à eliminação de materiais nucleares ou de outras substâncias radioactivas perigosas; 
  é punido com pena de prisão até 5 anos.
  3 - Quando as condutas descritas nos números anteriores forem suscetíveis de causar danos substanciais à qualidade do ar, da água ou do solo ou à fauna ou à flora, o agente é punido com pena de prisão até 3 anos ou com pena de multa até 600 dias.
  4 - Se as conduta','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s referidas nos n.os 1 e 2 forem praticadas por negligência, o agente é punido com pena de prisão até 2 anos ou com pena de multa até 360 dias.
  5 - Se as condutas referidas no n.º 3 forem praticadas por negligência, o agente é punido com pena de prisão até 1 ano ou com pena de multa até 240 dias.
  6 - Para os efeitos dos n.os 1, 2 e 3, são danos substanciais aqueles que: 
  a) Prejudiquem, de modo significativo ou duradouro, a integridade física, bem como o bem-estar das pessoas na fruição da natureza; 
  b) Impeçam, de modo significativo ou duradouro, a utilização de um componente ambiental; 
  c) Disseminem microrganismo ou substância prejudicial para o corpo ou saúde das pessoas; 
  d) Causem um impacto significativo sobre a conservação das espécies ou dos seus habitats; ou 
  e) Prejudiquem, de modo significativo, a qualidade ou o estado de um componente ambiental.
  7 - Quando forem efetuadas descargas de substâncias poluentes por navios, de forma isolada ou reiterada, das quais resulte deterioração da qualidade da água, o agente é punido com pena de prisão até 5 anos.
  8 - Se a conduta referida no número anterior for praticada por negligência, o agente é punido com pena de prisão até 2 anos ou com pena de multa até 360 dias.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 56/2011, de 15 de Novembro   - Lei n.º 81/2015, de 03 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro    - 3ª versão: Lei n.º 56/2011, de 15 de Novembro   
     
                         
                          
  Artigo 279.º-A Actividades perigosas para o ambiente
                            
                           
                             
                               
                             
     1 - Quem proceder à transferência de resíduos, quando essa actividade esteja abrangida pelo âmbito de aplicação do n.º 35 do artigo 2.º do Regulamento (CE) n.º 1013/2006, do Parlamento Europeu e do Conselho, de 14 de Junho, relativo à transferência de resíduos, e seja realizada em quantidades não negligenciáveis, quer consista numa transferência única quer em várias transferências aparentemente ligadas, é punido com pena de prisão até 3 anos ou com pena de multa até 600 dias. 
  2 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições, produzir, importar, exportar, colocar no mercado ou utilizar substâncias que empobreçam a camada de ozono é punido com pena de prisão até 1 ano ou com pena de multa até 240 dias. 
  3 - Se as condutas referidas nos números anteriores forem praticadas por negligência, o agente é punido com pena de prisão até 1 ano ou com pena de multa, nos casos do n.º 1, e com pena de prisão até 6 meses ou com pena de multa até 120 dias, nos casos do n.º 2.
  
  Aditado ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('pelo seguinte diploma: Lei n.º 56/2011, de 15 de Novembro            
         
   
     
                         
                          
  Artigo 280.º 
Poluição com perigo comum
                            
                           
                             
                               
                             
     Quem, mediante conduta descrita nos n.os 1, 2 e 7 do artigo 279.º, criar perigo para a vida ou para a integridade física de outrem, para bens patrimoniais alheios de valor elevado ou para monumentos culturais ou históricos, é punido com pena de prisão:
  a) De um a oito anos, se a conduta e a criação do perigo forem dolosas; 
  b) Até 6 anos, se a conduta for dolosa e a criação do perigo ocorrer por negligência.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 56/2011, de 15 de Novembro   - Lei n.º 81/2015, de 03 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro    - 3ª versão: Lei n.º 56/2011, de 15 de Novembro   
     
                         
                          
  Artigo 281.º Perigo relativo a animais ou vegetais
                            
                           
                             
                               
                             
     1 - Quem:
  a) Difundir doença, praga, planta ou animal nocivos; ou
  b) Manipular, fabricar ou produzir, importar, armazenar, ou puser à venda ou em circulação, alimentos ou forragens destinados a animais domésticos alheios; 
  e criar deste modo perigo de dano a número considerável de animais alheios, domésticos ou úteis ao homem, ou a culturas, plantações ou florestas alheias, é punido com pena de prisão até 2 anos ou com pena de multa. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até 1 ano ou com pena de multa até 240 dias. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até 6 meses ou com pena de multa até 120 dias.            
         
   
     
                         
                          
  Artigo 282.º Corrupção de substâncias alimentares ou medicinais
                            
                           
                             
                               
                             
     1 - Quem:
  a) No aproveitamento, produção, confecção, fabrico, embalagem, transporte, tratamento, ou outra actividade que sobre elas incida, de substâncias destinadas a consumo alheio, para serem comidas, mastigadas, bebidas, para fins medicinais ou cirúrgicos, as corromper, falsificar, alterar, reduzir o seu valor nutritivo ou terapêutico ou lhes juntar ingredientes; ou 
  b) Importar, dissimular, vender, expuser à venda, tiver em depósito para venda ou, por qualquer forma, entregar ao consumo alheio substâncias que forem object','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o de actividades referidas na alínea anterior ou que forem utilizadas depois do prazo da sua validade ou estiverem avariadas, corruptas ou alteradas por acção do tempo ou dos agentes a cuja acção estão expostas; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem é punido com pena de prisão de 1 a 8 anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até 5 anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até 3 anos ou com pena de multa.            
         
   
     
                         
                          
  Artigo 283.º Propagação de doença, alteração de análise ou de receituário
                            
                           
                             
                               
                             
     1 - Quem:
  a) Propagar doença contagiosa;
  b) Como médico ou seu empregado, enfermeiro ou empregado de laboratório, ou pessoa legalmente autorizada a elaborar exame ou registo auxiliar de diagnóstico ou tratamento médico ou cirúrgico, fornecer dados ou resultados inexactos; ou 
  c) Como farmacêutico ou empregado de farmácia fornecer substâncias medicinais em desacordo com o prescrito em receita médica; 
  e criar deste modo perigo para a vida ou perigo grave para a integridade física de outrem é punido com pena de prisão de 1 a 8 anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até 5 anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até 3 anos ou com pena de multa.            
         
   
     
                         
                          
  Artigo 284.º Recusa de médico
                            
                           
                             
                               
                             
     O médico que recusar o auxílio da sua profissão em caso de perigo para a vida ou de perigo grave para a integridade física de outra pessoa, que não possa ser removido de outra maneira, é punido com pena de prisão até 5 anos.            
         
   
     
                         
                          
  Artigo 285.º Agravação pelo resultado
                            
                           
                             
                               
                             
     Se dos crimes previstos nos artigos 272.º a 274.º, 277.º, 280.º, ou 282.º a 284.º resultar morte ou ofensa à integridade física grave de outra pessoa, o agente é punido com a pena que ao caso caberia, agravada de um terço nos seus limites mínimo e máximo.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
          ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                
  Artigo 286.º Atenuação especial e dispensa de pena
                            
                           
                             
                               
                             
     Se, nos casos previstos nos artigos 272.º a 274.º e 277.º, nos n.os 3 e 5 do artigo 279.º ou nos artigos 280.º a 284.º, o agente remover voluntariamente o perigo antes de se ter verificado dano substancial ou considerável, a pena é especialmente atenuada ou pode ter lugar a dispensa de pena.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 56/2011, de 15 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro   
     
                         
                          
CAPÍTULO IV
  Dos crimes contra a segurança das comunicações  Artigo 287.º Captura ou desvio de aeronave, navio, comboio ou veículo de transporte colectivo de passageiros
                            
                           
                             
                               
                             
     1 - Quem se apossar de, ou desviar da sua rota normal, aeronave em voo, ou navio em curso de navegação, nos quais se encontrem pessoas, é punido com pena de prisão de 5 a 15 anos. 
  2 - Quem se apossar de comboio em circulação no qual se encontrem pessoas, ou o desviar do seu trajecto normal, é punido com pena de prisão de 2 a 10 anos. 
  3 - Quem se apossar de, ou desviar da sua rota normal, veículo de transporte colectivo de passageiros em trânsito é punido com pena de prisão de 1 a 8 anos. 
  4 - Considera-se:
  a) Uma aeronave em voo desde o momento em que, terminado o embarque, tenham sido fechadas todas as portas exteriores até ao momento em que uma dessas portas seja aberta para o desembarque. Em caso de aterragem forçada o voo é considerado como estando a decorrer até que a autoridade competente se responsabilize pela aeronave, bem como pelas pessoas e bens a bordo; 
  b) Um navio em curso de navegação desde o momento em que o pessoal de terra ou a tripulação comecem as operações preparatórias de uma determinada viagem até à chegada a local de destino; 
  c) Um comboio em curso de circulação desde o momento em que, terminado o embarque de passageiros, se inicia a marcha até ao momento em que deva ter lugar o desembarque. 
  d) Um veículo de transporte colectivo de passageiros em trânsito desde o momento em que, terminado o embarque de passageiros, se inicia a marcha até ao momento em que deva ter lugar o desembarque.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 65/98, de 02 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 288.º Atentado à segurança de transporte por ar, água ou caminho de ferro
       ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                     
                           
                             
                               
                             
     1 - Quem atentar contra a segurança de transporte por ar, água ou caminho de ferro: 
  a) Destruindo, suprimindo, danificando ou tornando não utilizável instalação, material ou sinalização; 
  b) Colocando obstáculo ao funcionamento ou circulação; 
  c) Dando falso aviso ou sinal; ou 
  d) Praticando acto do qual possa resultar desastre; 
  é punido com pena de prisão de um a oito anos. 
  2 - Se, através da conduta referida no número anterior, o agente criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de três a dez anos. 
  3 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão de dois a oito anos. 
  4 - Se a conduta referida no n.º 2 for praticada por negligência, o agente é punido com pena de prisão até cinco anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 289.º Condução perigosa de meio de transporte por ar, água ou caminho de ferro
                            
                           
                             
                               
                             
     1 - Quem conduzir veículo destinado a transporte por ar, água ou caminho de ferro, não estando em condições de o fazer com segurança ou violando grosseiramente as regras de condução, e criar deste modo perigo para a vida ou para a integridade física de outrem ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de 1 a 8 anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até 5 anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até 3 anos ou com pena de multa.            
         
   
     
                         
                          
  Artigo 290.º Atentado à segurança de transporte rodoviário
                            
                           
                             
                               
                             
     1 - Quem atentar contra a segurança de transporte rodoviário: 
  a) Destruindo, suprimindo, danificando ou tornando não utilizável via de comunicação, material circulante, obra de arte, instalação ou sinalização; 
  b) Colocando obstáculo ao funcionamento ou à circulação; 
  c) Dando falso aviso ou sinal; ou 
  d) Praticando acto do qual possa resultar desastre; 
  é punido com pena de prisão de um a cinco anos. 
  2 - Se, através da conduta referida no número anterior, o agente criar perigo para a vida ou para a integridade física de outrem, o','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('u para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de dois a oito anos. 
  3 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão de um a cinco anos. 
  4 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até dois anos ou com pena de multa.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 291.º Condução perigosa de veículo rodoviário
                            
                           
                             
                               
                             
     1 - Quem conduzir veículo, com ou sem motor, em via pública ou equiparada: 
  a) Não estando em condições de o fazer com segurança, por se encontrar em estado de embriaguez ou sob influência de álcool, estupefacientes, substâncias psicotrópicas ou produtos com efeito análogo, ou por deficiência física ou psíquica ou fadiga excessiva; ou 
  b) Violando grosseiramente as regras da circulação rodoviária relativas à prioridade, à obrigação de parar, à ultrapassagem, à mudança de direcção, à passagem de peões, à inversão do sentido de marcha em auto-estradas ou em estradas fora de povoações, à marcha atrás em auto-estradas ou em estradas fora de povoações, ao limite de velocidade ou à obrigatoriedade de circular na faixa de rodagem da direita; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Quem conduzir veículo, com ou sem motor, em via pública ou equiparada e nela realizar actividades não autorizadas, de natureza desportiva ou análoga, que violem as regras previstas na alínea b) do número anterior, é punido com pena de prisão até três anos ou com pena de multa. 
  3 - Se o perigo referido no n.º 1 for criado por negligência, o agente é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  4 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até um ano ou com pena de multa até 120 dias.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2001, de 13 de Julho   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 77/2001, de 13 de Julho   
     
                         
                          
  Artigo 292.º Condução de veículo em estado de embriaguez ou sob a influência de estupefacientes ou substâncias psicotrópicas
                            
                           
                             
                               
                       ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('      
     1 - Quem, pelo menos por negligência, conduzir veículo, com ou sem motor, em via pública ou equiparada, com uma taxa de álcool no sangue igual ou superior a 1,2 g/l, é punido com pena de prisão até 1 ano ou com pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Na mesma pena incorre quem, pelo menos por negligência, conduzir veículo, com ou sem motor, em via pública ou equiparada, não estando em condições de o fazer com segurança, por se encontrar sob influência de estupefacientes, substâncias psicotrópicas ou produtos com efeito análogo perturbadores da aptidão física, mental ou psicológica.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2001, de 13 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 292.º-A 
Exercício de funções por pessoal crítico para a segurança da aviação civil em estado de embriaguez ou sob a influência de estupefacientes ou substâncias psicotrópicas
                            
                           
                             
                               
                             
     1 - Quem, pelo menos por negligência, exercer as suas funções de elemento do pessoal crítico para a segurança da aviação civil com uma taxa de álcool no sangue igual ou superior a 0,9 g/l é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias, se pena mais grave lhe não couber por força de outra disposição legal.
  2 - Na mesma pena incorre quem, pelo menos por negligência, exercer as suas funções de elemento do pessoal crítico para a segurança da aviação civil sob influência de estupefacientes, substâncias psicotrópicas ou produtos com efeito análogo perturbadores da aptidão física, mental ou psicológica, se pena mais grave lhe não couber por força de outra disposição legal.
  3 - Para efeitos do disposto nos números anteriores, entende-se por pessoal crítico para a segurança da aviação civil a tripulação das aeronaves, os pilotos remotos de aeronaves não tripuladas, o pessoal afeto à manutenção das aeronaves, os controladores de tráfego aéreo, os agentes de informação de tráfego de aeródromo, os oficiais de operações de voo, pessoal que efetua rastreios de segurança contra atos de interferência ilícita na aviação civil e qualquer outro pessoal que circule na área de movimento dos aeródromos.
  Aditado pelo seguinte diploma: Lei n.º 54/2023, de 04 de Setembro            
         
   
     
                         
                          
  Artigo 293.º 
Lançamento de projéctil contra veículo
                            
                           
                             
                               
                             
     1 - Quem arremessar projéctil contra veículo em movimento, de transporte por ar, água ou terra, é punido com pena de prisão até um ano ou c','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('om pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal.
  2 - Se o veículo em movimento, de transporte por ar, água ou terra, ou qualquer outro tipo de veículo, estiver afeto a agente das forças ou dos serviços de segurança, guarda prisional, ou bombeiro e demais agentes de proteção civil, o agressor é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias, se pena mais grave lhe não couber por força de outra disposição legal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro   - Lei n.º 26/2025, de 19 de Março
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março    - 2ª versão: Lei n.º 59/2007, de 04 de Setembro   
     
                         
                          
  Artigo 294.º Agravação, atenuação especial e dispensa de pena
                            
                           
                             
                               
                             
     1 - Quando os crimes previstos nos artigos 291.º e 292.º forem cometidos no exercício da respectiva actividade por condutores de veículos de transporte escolar, ligeiros de aluguer para transporte público de aluguer, pesados de passageiros ou de mercadorias ou de transporte de mercadorias perigosas, o agente é punido com a pena que ao caso caberia, agravada de um terço nos seus limites mínimo e máximo. 
  2 - É aplicável o disposto no número anterior aos condutores de veículos de socorro ou de emergência que cometam os crimes previstos na alínea a) do n.º 1 e nos n.os 2 e 3 do artigo 291.º e no artigo 292.º 
  3 - Aos casos previstos nos artigos 287.º a 291.º aplica-se o disposto nos artigos 285.º e 286.º, ainda que com as agravações previstas nos números anteriores.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2001, de 13 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
CAPÍTULO V
  Dos crimes contra a ordem e a tranquilidade públicas
  SECÇÃO I
  Dos crimes de anti-socialidade perigosa  Artigo 295.º Embriaguez e intoxicação
                            
                           
                             
                               
                             
     1 - Quem, pelo menos por negligência, se colocar em estado de inimputabilidade derivado da ingestão ou consumo de bebida alcoólica ou de substância tóxica e, nesse estado, praticar um facto ilícito típico é punido com pena de prisão até 5 anos ou com pena de multa até 600 dias. 
  2 - A pena não pode ser superior à prevista para o facto ilícito típico praticado. 
  3 - O procedimento criminal depende de queixa ou de acusação particular se o procedimento pelo facto ilícito típico praticado também dependesse de uma ou de outra.            
         
   
     
                     ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('    
                          
  Artigo 296.º Utilização de menor na mendicidade
                            
                           
                             
                               
                             
     Quem utilizar menor ou pessoa psiquicamente incapaz na mendicidade é punido com pena de prisão até três anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
SECÇÃO II
  Dos crimes contra a paz pública  Artigo 297.º Instigação pública a um crime
                            
                           
                             
                               
                             
     1 - Quem, em reunião pública, através de meio de comunicação social, por divulgação de escrito ou outro meio de reprodução técnica, provocar ou incitar à prática de um crime determinado é punido com pena de prisão até 3 anos ou com pena de multa, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - É correspondentemente aplicável o disposto no n.º 2 do artigo 295.º            
         
   
     
                         
                          
  Artigo 298.º Apologia pública de um crime
                            
                           
                             
                               
                             
     1 - Quem, em reunião pública, através de meio de comunicação social, por divulgação de escrito ou outro meio de reprodução técnica, recompensar ou louvar outra pessoa por ter praticado um crime, de forma adequada a criar perigo da prática de outro crime da mesma espécie, é punido com pena de prisão até 6 meses ou com pena de multa até 60 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - É correspondentemente aplicável o disposto no n.º 2 do artigo 295.º            
         
   
     
                         
                          
  Artigo 299.º Associação criminosa
                            
                           
                             
                               
                             
     1 - Quem promover ou fundar grupo, organização ou associação cuja finalidade ou actividade seja dirigida à prática de um ou mais crimes é punido com pena de prisão de um a cinco anos. 
  2 - Na mesma pena incorre quem fizer parte de tais grupos, organizações ou associações ou quem os apoiar, nomeadamente fornecendo armas, munições, instrumentos de crime, guarda ou locais para as reuniões, ou qualquer auxílio para que se recrutem novos elementos. 
  3 - Quem chefiar ou dirigir os grupos, organizações ou associações referidos nos números anteriores é punido com pena de prisão de dois a oito anos. 
  4 - As penas referidas podem ser especialmente atenuadas ou não ter lugar a punição se o agente imp','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('edir ou se esforçar seriamente por impedir a continuação dos grupos, organizações ou associações, ou comunicar à autoridade a sua existência de modo a esta poder evitar a prática de crimes. 
  5 - Para os efeitos do presente artigo, considera-se que existe grupo, organização ou associação quando esteja em causa um conjunto de, pelo menos, três pessoas, actuando concertadamente durante um certo período de tempo.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 59/2007, de 04 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 300.º Organizações terroristas
                            
                           
                             
                               
                             
     Revogado pela Lei n.º 52/2003, de 22 de Agosto            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 52/2003, de 22 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 301.º Terrorismo
                            
                           
                             
                               
                             
     Revogado pela Lei n.º 52/2003, de 22 de Agosto            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 52/2003, de 22 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 302.º Participação em motim
                            
                           
                             
                               
                             
     1 - Quem tomar parte em motim durante o qual forem cometidas colectivamente violências contra pessoas ou contra a propriedade é punido com pena de prisão até 1 ano ou com pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Se o agente tiver provocado ou dirigido o motim, é punido com pena de prisão até 3 anos ou com pena de multa. 
  3 - O agente não é punido se se tiver retirado do motim por ordem ou admoestação da autoridade sem ter cometido ou provocado violência.            
         
   
     
                         
                          
  Artigo 303.º Participação em motim armado
                            
                           
                             
                               
                             
     1 - Os limites mínimo e máximo das penas previstas nos n.os 1 e 2 do artigo anterior são elevados ao dobro se o motim for armado. 
  2 - Considera-se armado o motim em que um dos intervenientes é portador de arma de fogo ostensiva, ou em que vários dos participantes são portadores de armas de fogo, ostensivas ou ocultas, ou ','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('de objectos, ostensivos ou ocultos, susceptíveis de serem utilizados como tal. 
  3 - Para efeito do disposto no número anterior não se considera armado o motim: 
  a) Em que as armas são trazidas acidentalmente e sem intenção de as utilizar; ou 
  b) Quando os participantes que tragam armas imediatamente se retirarem ou forem expulsos. 
  4 - Quem trouxer arma sem conhecimento dos outros é punido como se efectivamente participasse em motim armado. 
  5 - É correspondentemente aplicável o disposto no n.º 3 do artigo anterior.            
         
   
     
                         
                          
  Artigo 304.º Desobediência a ordem de dispersão de reunião pública
                            
                           
                             
                               
                             
     1 - Quem não obedecer a ordem legítima de se retirar de ajuntamento ou reunião pública, dada por autoridade competente, com advertência de que a desobediência constitui crime, é punido com pena de prisão até 1 ano ou com pena de multa até 120 dias. 
  2 - Se o desobediente for promotor da reunião ou ajuntamento, é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.            
         
   
     
                         
                          
  Artigo 305.º Ameaça com prática de crime
                            
                           
                             
                               
                             
     Quem, mediante ameaça com a prática de crime, ou fazendo crer simuladamente que um crime vai ser cometido, causar alarme ou inquietação entre a população é punido com pena de prisão até 2 anos ou com pena de multa até 240 dias.            
         
   
     
                         
                          
  Artigo 306.º Abuso e simulação de sinais de perigo
                            
                           
                             
                               
                             
     Quem utilizar abusivamente sinal ou chamada de alarme ou de socorro, ou simuladamente fizer crer que é necessário auxílio alheio em virtude de desastre, perigo ou situação de necessidade colectiva, é punido com pena de prisão até l ano ou com pena de multa até 120 dias.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Declaração n.º 73-A/95, de 14 de Junho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
SECÇÃO III
  Dos crimes contra sinais de identificação  Artigo 307.º Abuso de designação, sinal ou uniforme
                            
                           
                             
                               
                             
     1 - Quem, ilegitimamente e com intenção de fazer crer que lhe pertencem, utilizar ou usar designação, sinal, uniforme ou traje próprios de função do serviço público, na','447');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('cional ou estrangeiro, é punido com pena de prisão até 6 meses ou com pena de multa até 60 dias. 
  2 - Se a designação, sinal, uniforme ou traje for privativo de pessoa que exerça autoridade pública, o agente é punido com pena de prisão até 1 ano ou com pena de multa até 120 dias.            
         
   
     
                         
                          
TÍTULO VDos crimes contra o EstadoCAPÍTULO IDos crimes contra a segurança do EstadoSECÇÃO IDos crimes contra a soberania nacionalSUBSECÇÃO IDos crimes contra a independência e a integridade nacionais  Artigo 308.º Traição à pátria
                            
                           
                             
                               
                             
     Aquele que, por meio de usurpação ou abuso de funções de soberania:
  a) Tentar separar da Mãe-Pátria ou entregar a país estrangeiro ou submeter à soberania estrangeira todo o território português ou parte dele; ou 
  b) Ofender ou puser em perigo a independência do País;
  é punido com pena de prisão de 10 a 20 anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 100/2003, de 15 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 48/95, de 15 de Março   
     
                         
                          
  Artigo 309.º Serviço militar em forças armadas inimigas
                            
                           
                             
                               
                             
     (Revogado pela Lei n.º 100/2003, de 15 Novembro)            
         
